const resolveSessionTurnHead = `-- name: ResolveSessionTurnHead :one
WITH RECURSIVE descendant_turns AS (
  SELECT t.id
  FROM bot_history_turns t
  WHERE t.id = $2
  UNION ALL
  SELECT c.id
  FROM bot_history_turns c
  JOIN descendant_turns dt ON c.parent_turn_id = dt.id
)
SELECT h.head_turn_id
FROM bot_session_turn_heads h
WHERE h.session_id = $1
  AND h.head_turn_id IN (SELECT dt.id FROM descendant_turns dt)
ORDER BY h.updated_at DESC, h.head_turn_id DESC
LIMIT 1
`

type ResolveSessionTurnHeadParams struct {
	SessionID    pgtype.UUID `json:"session_id"`
	TargetTurnID pgtype.UUID `json:"target_turn_id"`
}

// Resolve any turn id to a session head whose ancestor path contains it
// (a head contains the turn exactly when the head is one of the turn's
// descendants, self included), preferring the most recently updated head.
// Used when a client pages with a non-head turn id (variant switching);
// true heads short-circuit through the cheap heads-table lookup before this
// recursion runs.
func (q *Queries) ResolveSessionTurnHead(ctx context.Context, arg ResolveSessionTurnHeadParams) (pgtype.UUID, error) {
	row := q.db.QueryRow(ctx, resolveSessionTurnHead, arg.SessionID, arg.TargetTurnID)
	var head_turn_id pgtype.UUID
	err := row.Scan(&head_turn_id)
	return head_turn_id, err
}

const searchMessages = `-- name: SearchMessages :many
WITH RECURSIVE visible_turns AS (
  SELECT t.id, t.parent_turn_id, 0::bigint AS depth
  FROM bot_sessions bs
  JOIN bot_history_turns t ON t.id = bs.default_head_turn_id
    AND t.bot_id = bs.bot_id
  WHERE $2::uuid IS NOT NULL
    AND bs.id = $2::uuid
    AND bs.deleted_at IS NULL
  UNION ALL
  SELECT p.id, p.parent_turn_id, vt.depth + 1
  FROM bot_history_turns p
  JOIN visible_turns vt ON vt.parent_turn_id = p.id
)
SELECT
  m.id,
  m.bot_id,
  m.session_id,
  m.sender_channel_identity_id,
  m.role,
  m.content,
  m.created_at,
  ci.display_name AS sender_display_name,
  s.channel_type AS platform
FROM bot_history_messages m
LEFT JOIN channel_identities ci ON ci.id = m.sender_channel_identity_id
LEFT JOIN bot_sessions s ON s.id = m.session_id
WHERE m.bot_id = $1
  AND ($2::uuid IS NULL OR m.turn_id IN (SELECT id FROM visible_turns))
  AND ($3::uuid IS NULL OR m.sender_channel_identity_id = $3::uuid)
  AND ($4::timestamptz IS NULL OR m.created_at >= $4::timestamptz)
  AND ($5::timestamptz IS NULL OR m.created_at <= $5::timestamptz)
  AND ($6::text IS NULL OR m.role = $6::text)
  AND ($7::text IS NULL OR (
    CASE
      WHEN jsonb_typeof(m.content->'content') = 'string'
        THEN m.content->>'content'
      WHEN jsonb_typeof(m.content->'content') = 'array'
        THEN (SELECT COALESCE(string_agg(elem->>'text', ' '), '')
              FROM jsonb_array_elements(m.content->'content') AS elem
              WHERE elem->>'type' = 'text')
      ELSE ''
    END
  ) ILIKE '%' || $7::text || '%')
ORDER BY m.created_at DESC
LIMIT $8
`

type SearchMessagesParams struct {
	BotID     pgtype.UUID        `json:"bot_id"`
	SessionID pgtype.UUID        `json:"session_id"`
	ContactID pgtype.UUID        `json:"contact_id"`
	StartTime pgtype.Timestamptz `json:"start_time"`
	EndTime   pgtype.Timestamptz `json:"end_time"`
	Role      pgtype.Text        `json:"role"`
	Keyword   pgtype.Text        `json:"keyword"`
	MaxCount  int32              `json:"max_count"`
}

type SearchMessagesRow struct {
	ID                      pgtype.UUID        `json:"id"`
	BotID                   pgtype.UUID        `json:"bot_id"`
	SessionID               pgtype.UUID        `json:"session_id"`
	SenderChannelIdentityID pgtype.UUID        `json:"sender_channel_identity_id"`
	Role                    string             `json:"role"`
	Content                 []byte             `json:"content"`
	CreatedAt               pgtype.Timestamptz `json:"created_at"`
	SenderDisplayName       pgtype.Text        `json:"sender_display_name"`
	Platform                pgtype.Text        `json:"platform"`
}

// Session-scoped search follows bot_sessions.default_head_turn_id. The client
// selected variant is intentionally not part of this tool/query contract.
func (q *Queries) SearchMessages(ctx context.Context, arg SearchMessagesParams) ([]SearchMessagesRow, error) {
	rows, err := q.db.Query(ctx, searchMessages,
		arg.BotID,
		arg.SessionID,
		arg.ContactID,
		arg.StartTime,
		arg.EndTime,
		arg.Role,
		arg.Keyword,
		arg.MaxCount,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []SearchMessagesRow
	for rows.Next() {
		var i SearchMessagesRow
		if err := rows.Scan(
			&i.ID,
			&i.BotID,
			&i.SessionID,
			&i.SenderChannelIdentityID,
			&i.Role,
			&i.Content,
			&i.CreatedAt,
			&i.SenderDisplayName,
			&i.Platform,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

